const fs = require('fs');
const path = require('path');

const manifestPath = $json.path;
const raw = fs.readFileSync(manifestPath, 'utf8');
const lines = raw.split(/\r?\n/).filter(l => l.trim().length > 0);

if (lines.length < 2) {
  throw new Error('Manifest has no clip rows: ' + manifestPath);
}

function parseCsvLine(line) {
  const cols = [];
  let cur = '';
  let inQuote = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inQuote && line[i + 1] === '"') { cur += '"'; i++; }
      else { inQuote = !inQuote; }
    } else if (ch === ',' && !inQuote) {
      cols.push(cur); cur = '';
    } else {
      cur += ch;
    }
  }
  cols.push(cur);
  return cols.map(s => s.trim());
}

const header = parseCsvLine(lines[0]);
const jobDir = path.dirname(manifestPath);

const items = [];
for (let i = 1; i < lines.length; i++) {
  const vals = parseCsvLine(lines[i]);
  const row = {};
  header.forEach((h, idx) => { row[h] = vals[idx] !== undefined ? vals[idx] : ''; });
  row.clipIndex = i - 1;
  row.jobDir = jobDir;
  row.manifestPath = manifestPath;
  // Resolve relative export_path against jobDir
  if (row.export_path && !path.isAbsolute(row.export_path)) {
    row.export_path = path.join(jobDir, row.export_path);
  }
  items.push({ json: row });
}

return items;

const { DateTime } = require('luxon');

const REGIONS = [
  { tz: 'Africa/Johannesburg', hours: [12, 18, 20] },
  { tz: 'America/New_York',    hours: [12, 18, 20] },
  { tz: 'America/Los_Angeles', hours: [12, 18, 20] },
  { tz: 'Europe/London',       hours: [12, 19, 21] }
];
const MIN_LEAD_MIN = 10;
const DEDUP_MIN = 30;

const now = DateTime.utc();
const raw = [];

for (let day = 0; day < 7; day++) {
  for (const r of REGIONS) {
    for (const h of r.hours) {
      const utc = DateTime.now().setZone(r.tz)
        .startOf('day').plus({ days: day, hours: h }).toUTC();
      if (utc.diff(now, 'minutes').minutes >= MIN_LEAD_MIN) {
        raw.push(utc);
      }
    }
  }
}

raw.sort((a, b) => a.toMillis() - b.toMillis());

const windows = [];
for (const w of raw) {
  const last = windows[windows.length - 1];
  if (!last || w.diff(last, 'minutes').minutes >= DEDUP_MIN) {
    windows.push(w);
  }
}

if (windows.length === 0) {
  throw new Error('No peak windows available in 7-day lookahead');
}

return $input.all().map(item => ({
  json: {
    ...item.json,
    scheduledAt: windows[item.json.clipIndex % windows.length].toISO()
  }
}));

const fs = require('fs');
const filePath = $('Read Clip File').item.json.export_path;
const out = { ...$('Read Clip File').item.json };

try {
  const init = $json;
  if (!init || !init.data || !init.data.upload_url || !init.data.publish_id) {
    throw new Error('TikTok init failed: ' + JSON.stringify(init).substring(0, 300));
  }
  const uploadUrl = init.data.upload_url;
  out.tiktok_publish_id = init.data.publish_id;

  const CHUNK = 10 * 1024 * 1024;
  const stat = fs.statSync(filePath);
  const total = stat.size;
  const fd = fs.openSync(filePath, 'r');
  let offset = 0;

  while (offset < total) {
    const len = Math.min(CHUNK, total - offset);
    const buf = Buffer.alloc(len);
    fs.readSync(fd, buf, 0, len, offset);
    const resp = await this.helpers.httpRequest({
      method: 'PUT',
      url: uploadUrl,
      body: buf,
      headers: {
        'Content-Type': 'video/mp4',
        'Content-Length': String(len),
        'Content-Range': `bytes ${offset}-${offset + len - 1}/${total}`
      },
      returnFullResponse: true,
      encoding: null
    });
    if (resp.statusCode >= 400) {
      throw new Error(`Chunk ${offset} upload failed: HTTP ${resp.statusCode}`);
    }
    offset += len;
  }
  fs.closeSync(fd);
  out.tiktok_upload_status = 'uploaded';
} catch (err) {
  out.tiktok_error = String(err.message || err);
  out.tiktok_upload_status = 'failed';
}

return [{ json: out, binary: $binary }];

// Extract Location header from full-response YouTube Init output
const resp = $json;
const out = { ...$('Read Clip File').item.json };
try {
  const headers = (resp && resp.headers) || {};
  const sessionUrl = headers.location || headers.Location;
  if (!sessionUrl) {
    throw new Error('YouTube init missing Location header: ' + JSON.stringify(resp).substring(0, 300));
  }
  out.youtube_session_url = sessionUrl;
} catch (err) {
  out.youtube_error = String(err.message || err);
}
return [{ json: out, binary: $binary }];

const fs = require('fs');
const path = require('path');

const HEADER = 'timestamp,filename,title,tiktok_publish_id,tiktok_status,youtube_video_id,youtube_status,error\n';

function csvEscape(v) {
  const s = String(v == null ? '' : v);
  return (s.includes(',') || s.includes('"') || s.includes('\n'))
    ? '"' + s.replace(/"/g, '""') + '"'
    : s;
}

const out = [];
for (const item of $input.all()) {
  const j = item.json;
  const logPath = path.join(j.jobDir, 'results.log.csv');

  const tiktokStatus = j.tiktok_upload_status || (j.data && j.data.status) || '';
  const youtubeId    = (j.id) || (j.body && j.body.id) || '';
  const youtubeStatus = j.youtube_error ? 'failed' : (youtubeId ? 'uploaded' : 'unknown');
  const errors = [j.tiktok_error, j.youtube_error].filter(Boolean).join(' | ');

  const row = [
    new Date().toISOString(),
    j.filename || path.basename(j.export_path || ''),
    j.title || '',
    j.tiktok_publish_id || '',
    tiktokStatus,
    youtubeId,
    youtubeStatus,
    errors
  ].map(csvEscape).join(',') + '\n';

  if (!fs.existsSync(logPath)) fs.writeFileSync(logPath, HEADER);
  fs.appendFileSync(logPath, row);

  if (errors) {
    try {
      const token = process.env.TELEGRAM_BOT_TOKEN;
      const chatId = process.env.TELEGRAM_CHAT_ID;
      if (token && chatId) {
        await this.helpers.httpRequest({
          method: 'POST',
          url: `https://api.telegram.org/bot${token}/sendMessage`,
          json: true,
          body: {
            chat_id: chatId,
            text: `Reelsmith publish FAILED\nfile: ${j.filename || j.export_path}\nerror: ${errors}`
          }
        });
      }
    } catch (_) { /* swallow alert errors */ }
  }

  out.push({ json: { ...j, logged: true } });
}
return out;

const fs = require('fs');
const path = require('path');

const items = $input.all();
const out = [];

for (let i = 0; i < items.length; i++) {
  const j = items[i].json;
  // Archive on last item only — one manifest per execution
  if (i === items.length - 1) {
    const src = j.manifestPath;
    if (src && fs.existsSync(src)) {
      const processedDir = path.join(j.jobDir, 'processed');
      fs.mkdirSync(processedDir, { recursive: true });
      const stamp = new Date().toISOString().replace(/[:.]/g, '-');
      const dest = path.join(processedDir, `manifest-${stamp}.csv`);
      fs.renameSync(src, dest);
      out.push({ json: { ...j, archived_to: dest } });
      continue;
    }
  }
  out.push({ json: j });
}
return out;
